sql:
SELECT declaration_date
FROM disasters
WHERE state = 'California';

SELECT COUNT(*) AS total_designated_areas
FROM designated_areas
WHERE disaster_number = 0;

SELECT designated_area
FROM designated_areas
WHERE area_recovery_status = 'Ongoing';

SELECT SUM(affected_population) AS total_affected_population
FROM disasters
WHERE state = 'NC';

SELECT designated_area
FROM designated_areas
WHERE disaster_number = 1;

SELECT disaster_description
FROM disasters
WHERE disaster_number = 1;

SELECT SUM(area_damage_cost) AS total_damage_cost
FROM designated_areas
WHERE disaster_number = 1;

SELECT disaster_number, last_refresh
FROM refresh_logs
ORDER BY last_refresh DESC;

SELECT AVG(estimated_damage_cost) AS average_damage_cost
FROM disasters
WHERE state = 'NC' AND disaster_severity = 'High';

external_knowledge:
- A disaster is considered ongoing if it has no recovery end date recorded; 
- Exceeding $10 million refers to the estimated damage cost being greater than $10,000,000; 
- Total aid allocated is the sum of Individual Assistance, Public Assistance, and Hazard Mitigation amounts.
